        ELSIF (Drone2BatteryLevel < 20) AND (NOT DroneDeployed) THEN
            state := 2; (* CHARGING_DRONE2 *)
            TimeRemaining := ChargingTime;
            chargingDrone := 2;
        ELSIF (Drone3BatteryLevel < 20) AND (NOT DroneDeployed) THEN
